1	// cli.ts
2	import {
3	  quote,
4	  claim,
5	  insuranceSum,
6	  isKnownItemType,
7	  type Item,
8	} from "./claim-office.js";
9	
10	type QuoteStep = { op: "quote"; items: Item[] };
11	type ClaimStep = {
12	  op: "claim";
13	  policy: number;
14	  incident: { cause: string; damages: { itemType: string; amount: number }[] };
15	};
16	type Step = QuoteStep | ClaimStep;
17	
18	type Scenario = {
19	  customer: { yearsWithMHPCO: number };
20	  steps: Step[];
21	};
22	
23	type Policy = {
24	  items: Item[];
25	  remainingCap: number;
26	};
27	
28	type StepResult = { premium: number } | { payout: number; remainingCap: number };
29	
30	const CAP_MULTIPLIER = 2;
31	
32	async function readStdin(): Promise<string> {
33	  const chunks: Buffer[] = [];
34	  for await (const chunk of process.stdin) {
35	    chunks.push(chunk as Buffer);
36	  }
37	  return Buffer.concat(chunks).toString("utf8");
38	}
39	
40	function fail(message: string): never {
41	  console.error(message);
42	  process.exit(1);
43	}
44	
45	function validateItems(items: Item[]): void {
46	  for (const item of items) {
47	    if (!isKnownItemType(item.type)) {
48	      fail(`Unknown item type: ${item.type}`);
49	    }
50	  }
51	}
52	
53	function processQuote(
54	  step: QuoteStep,
55	  customerYears: number,
56	  previousContracts: number,
57	  policies: Policy[],
58	): StepResult {
59	  validateItems(step.items);
60	  const premium = quote({
61	    items: step.items,
62	    customerYears,
63	    previousContracts,
64	  });
65	  policies.push({
66	    items: step.items,
67	    remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
68	  });
69	  return { premium };
70	}
71	
72	function countByType<T>(items: T[], getType: (item: T) => string): Map<string, number> {
73	  const counts = new Map<string, number>();
74	  for (const item of items) {
75	    const key = getType(item);
76	    counts.set(key, (counts.get(key) ?? 0) + 1);
77	  }
78	  return counts;
79	}
80	
81	function validateDamages(damages: { itemType: string; amount: number }[], policyItems: Item[]): void {
82	  for (const damage of damages) {
83	    if (damage.amount < 0) {
84	      fail(`Damage amount cannot be negative: ${damage.amount}`);
85	    }
86	  }
87	  const damageCounts = countByType(damages, (d) => d.itemType);
88	  const policyCounts = countByType(policyItems, (i) => i.type);
89	  for (const [itemType, count] of damageCounts) {
90	    if (count > (policyCounts.get(itemType) ?? 0)) {
91	      fail(`More damages of type ${itemType} than policy covers`);
92	    }
93	  }
94	}
95	
96	function processClaim(step: ClaimStep, policies: Policy[]): StepResult {
97	  const policy = policies[step.policy];
98	  validateDamages(step.incident.damages, policy.items);
99	  const result = claim({
100	    items: policy.items,
101	    remainingCap: policy.remainingCap,
102	    damages: step.incident.damages,
103	  });
104	  policy.remainingCap = result.remainingCap;
105	  return result;
106	}
107	
108	async function main() {
109	  const raw = await readStdin();
110	  const scenario: Scenario = JSON.parse(raw);
111	
112	  const results: StepResult[] = [];
113	  const policies: Policy[] = [];
114	  let previousContracts = 0;
115	
116	  for (const step of scenario.steps) {
117	    if (step.op === "quote") {
118	      results.push(
119	        processQuote(step, scenario.customer.yearsWithMHPCO, previousContracts, policies),
120	      );
121	      previousContracts += 1;
122	    } else {
123	      results.push(processClaim(step, policies));
124	    }
125	  }
126	
127	  console.log(JSON.stringify({ results }));
128	}
129	
130	main().catch((err) => {
131	  console.error(err instanceof Error ? err.message : String(err));
132	  process.exit(1);
133	});
